// Get workflow static data (persists between runs)
const workflowData = $getWorkflowStaticData('global');

// Initialize last run time if not set
if (!workflowData.lastRunTime) {
  workflowData.lastRunTime = '2026-01-01 00:00:00';
}

const lastRunTime = workflowData.lastRunTime;
const currentRunTime = new Date().toISOString().replace('T', ' ').substring(0, 19);

// Filter hosts created after last run
const newHosts = items[0].json.hosts.filter(host => {
  // Parse createdTime (format: "2026-01-24 16:10:27")
  const createdTime = host.createdTime;

  // Simple string comparison (works for this format)
  return createdTime > lastRunTime;
});

// Update last run time for next execution
workflowData.lastRunTime = currentRunTime;

// Return filtered hosts
return newHosts.map(host => ({
  json: host
}));

// Filter hosts that have inventory data
const hostsWithInventory = items.filter(item => {
  const host = item.json;

  // Check if inventory exists and has data
  if (!host.inventory) return false;

  // Check if inventory has an ID (means it's populated)
  if (!host.inventory.id) return false;

  // Check for valid serial number
  const serial = host.inventory.sysserial;
  if (!serial || 
      serial === 'System Serial Number' || 
      serial === 'To be filled by O.E.M.' ||
      serial === 'Default string') {
    return false;
  }

  return true;
});

return hostsWithInventory;

// Get the FOG host data
const fogHost = items[0].json;

// Check if we have inventory data
if (!fogHost || !fogHost.inventory) {
  return [{
    json: {
      name: 'ERROR-NoInventory',
      serial: 'ERROR',
      comment: 'No inventory data in FOG response',
      model: 'Unknown',
      type: 'Laptop',
      states_id: 1,
      locations_id: 1,
      users_id: 0,
      groups_id: 0,
      computermodels_id: 1,
      computertypes_id: 1,
      manufacturers_id: 1,
      is_dynamic: 1,
      otherserial: 'Unknown'
    }
  }];
}

// Get inventory data
const inventory = fogHost.inventory;

// Process the data
const manufacturer = inventory.sysman || '';
const model = inventory.sysproduct || '';
const glpiModel = `${manufacturer.toUpperCase().split(' ')[0]} ${model}`;

const fogType = inventory.systype || '';
const glpiType = fogType.includes('Notebook') || fogType.includes('Laptop') ? 'Laptop' : 
                 fogType.includes('Desktop') ? 'Desktop' : 
                 fogType.includes('Server') ? 'Server' : 'Laptop';

const memoryText = inventory.memory || '0.00 GiB';
const memoryGiB = parseFloat(memoryText.replace(' GiB', '')) || 0;
const memoryMB = Math.round(memoryGiB * 1024);

const comment = `FOG Import: ${manufacturer} ${model}
CPU: ${inventory.cpuversion || 'Unknown'}
RAM: ${memoryText}
Storage: ${inventory.hdmodel || 'Unknown'}
MAC: ${fogHost.primac || 'Unknown'}`;

// Map manufacturer name to GLPI manufacturer ID
// USING YOUR ACTUAL GLPI MANUFACTURER IDs
let manufacturers_id = 1; // Default to "Unknown" (ID 1 = XXXX)

const manufacturerLower = manufacturer.toLowerCase();

if (manufacturerLower.includes('dell')) manufacturers_id = 7;
if (manufacturerLower.includes('hp')) manufacturers_id = 6;
if (manufacturerLower.includes('hewlett')) manufacturers_id = 6; // Hewlett-Packard
if (manufacturerLower.includes('lenovo')) manufacturers_id = 5;
if (manufacturerLower.includes('apple')) manufacturers_id = 9;
if (manufacturerLower.includes('asus')) manufacturers_id = 13;
if (manufacturerLower.includes('samsung')) manufacturers_id = 10;
if (manufacturerLower.includes('microsoft')) manufacturers_id = 12;
if (manufacturerLower.includes('intel')) manufacturers_id = 2;
if (manufacturerLower.includes('amd')) manufacturers_id = 11;
if (manufacturerLower.includes('fujitsu')) manufacturers_id = 8;

// Map type to GLPI computertypes_id
let computertypes_id = 1; // Default to "Desktop"
if (glpiType === 'Laptop') computertypes_id = 2; // Example ID for Laptop
if (glpiType === 'Server') computertypes_id = 3; // Example ID for Server

// Model lookup logic
let modelId = 1; // Default to ID 1 ("Dell" generic model)

// Check if we have ComputerModel data (from connected node)
if (items[1] && items[1].json) {
  const computerModels = Array.isArray(items[1].json) ? items[1].json : [items[1].json];

  // Create search model name: "Dell Latitude 3520"
  const searchModel = `Dell ${model}`;

  // Look for exact match
  const foundModel = computerModels.find(m => m.name === searchModel);

  if (foundModel) {
    modelId = foundModel.id;
  } else {
    // Try partial match (contains "Latitude")
    const partialMatch = computerModels.find(m => m.name && m.name.includes("Latitude"));
    if (partialMatch) {
      modelId = partialMatch.id; // Use any Latitude model
    }
    // Otherwise keep default ID 1
  }
}

// Return processed data in GLPI format
return [{
  json: {
    // GLPI required fields
    name: fogHost.name || `FOG-${inventory.sysserial}`,
    serial: inventory.sysserial || '',
    comment: comment,

    // GLPI IDs (you need to check your actual GLPI IDs)
    computermodels_id: modelId,  // Uses looked-up model ID
    computertypes_id: computertypes_id,
    manufacturers_id: manufacturers_id,
    states_id: 1,                // Default state ID
    locations_id: 1,             // Default location ID
    users_id: 0,                 // 0 = no user assigned
    groups_id: 0,                // 0 = no group assigned

    // Additional GLPI fields
    is_dynamic: 1,               // IMPORTANT: 1 for inventory imports
    otherserial: fogHost.primac || '',  // Store MAC address here

    // Optional: You can also send these if your GLPI has them
    memory: memoryMB,            // Memory in MB
    processors_id: 1,            // Default processor ID
    computertypes_id: computertypes_id
  }
}];

// Pull all items directly from each GLPI node by name
const manufacturers = $('Get GLPI Computer Manufacturer').all().map(i => i.json);
const computerTypes = $('Get GLPI Computer Type').all().map(i => i.json);
const models = $('Get GLPI Computer Models').all().map(i => i.json);
const processors = $('Get Processor Data').all().map(i => i.json);
const memory = $('Get Memory Data').all().map(i => i.json);

return [{
  json: {
    manufacturers,
    computer_types: computerTypes,
    models,
    processors,
    memory,
    counts: {
      manufacturers: manufacturers.length,
      computer_types: computerTypes.length,
      models: models.length,
      processors: processors.length,
      memory: memory.length
    }
  }
}];

// Input 0: FOG hosts (if connected)
// Input 1: GLPI Manufacturers
// Input 2: GLPI Models  
// Input 3: GLPI Processors
// Input 4: GLPI Memory

// Get each input array
const fogHosts = items[0]?.json || [];
const glpiManufacturers = items[1]?.json || [];
const glpiModels = items[2]?.json || [];
const glpiProcessors = items[3]?.json || [];
const glpiMemory = items[4]?.json || [];

// Store in flow variables for later use
$set('glpi_manufacturers', glpiManufacturers);
$set('glpi_models', glpiModels);
$set('glpi_processors', glpiProcessors);
$set('glpi_memory', glpiMemory);

// Return summary
return [{
  json: {
    // Store all separated data
    fog_hosts: fogHosts,
    glpi_manufacturers: glpiManufacturers,
    glpi_models: glpiModels,
    glpi_processors: glpiProcessors,
    glpi_memory: glpiMemory,

    // For processing
    total_fog_hosts: fogHosts.length,
    total_glpi_manufacturers: glpiManufacturers.length,
    total_glpi_models: glpiModels.length,
    total_glpi_processors: glpiProcessors.length,
    total_glpi_memory: glpiMemory.length,

    // Debug info
    input_count: items.length
  }
}];

// Get GLPI reference data from the earlier node
const refs = $('Separate combied data').first().json;

// Current FOG host
const host = $input.item.json;
const inv = host.inventory;

// Extract FOG values
const fogManufacturer = inv.sysman || '';
const fogModel = inv.sysproduct || '';
const fogCpu = (inv.cpuversion || '').split('@')[0].trim();
const fogMemGb = Math.round(parseFloat((inv.memory || '0').replace(' GiB', '')));
const fogSystype = inv.systype || '';

// Lookup functions (case-insensitive)
const findManufacturer = name => refs.manufacturers.find(m => m.name.toLowerCase() === name.toLowerCase());
const findModel = name => refs.models.find(m => m.name.toLowerCase() === name.toLowerCase());
const findCpu = name => refs.processors.find(p => p.designation.toLowerCase() === name.toLowerCase());
const findMemory = gb => refs.memory.find(m => m.designation.toLowerCase() === `${gb}gb`);
const findType = type => refs.computer_types.find(t => t.name.toLowerCase() === type.toLowerCase());

const manufacturer = findManufacturer(fogManufacturer);
const model = findModel(fogModel);
const cpu = findCpu(fogCpu);
const memory = findMemory(fogMemGb);
const computerType = findType(fogSystype);

return {
  json: {
    fog_id: host.id,
    serial: inv.sysserial,
    mac: host.primac,
    manufacturer: { value: fogManufacturer, glpi_id: manufacturer?.id || null, exists: !!manufacturer },
    model: { value: fogModel, glpi_id: model?.id || null, exists: !!model },
    cpu: { value: fogCpu, glpi_id: cpu?.id || null, exists: !!cpu },
    memory: { value: `${fogMemGb}GB`, glpi_id: memory?.id || null, exists: !!memory },
    computer_type: { value: fogSystype, glpi_id: computerType?.id || null, exists: !!computerType }
  }
};

const sessionToken = $input.item.json.session_token;
const workflowData = $getWorkflowStaticData('global');
workflowData.session_token = sessionToken;
return $input.item;

// Extract Specs from FOG Hosts
// Input: Array of items, each with a host object in items[i].json
// Output: Array of normalized specs for cache lookup

const results = [];

// Normalization function
function normalizeName(value) {
  if (!value || typeof value !== 'string') return 'Unknown';

  return value
    .toLowerCase()
    .replace(/^type:\s*/i, '') // Remove "Type: " prefix
    .replace(/\s*\([^)]*\)/g, '') // Remove parentheses content
    .replace(/\s+/g, ' ') // Normalize whitespace
    .trim();
}

// Process each item
for (const item of items) {
  const fogHost = item.json;

  // Check if we have inventory data
  if (!fogHost || !fogHost.inventory) {
    results.push({
      json: {
        error: 'No inventory data',
        fog_host_id: fogHost?.id || 'unknown',
        normalized_manufacturer: 'Unknown',
        normalized_model: 'Unknown',
        normalized_processor: 'Unknown',
        normalized_memory: 'Unknown',
        normalized_storage: 'Unknown',
        normalized_computer_type: 'Unknown'
      }
    });
    continue;
  }

  const inventory = fogHost.inventory;

  // Extract and normalize specs
  const normalized_manufacturer = normalizeName(inventory.sysman || 'Unknown');
  const normalized_model = normalizeName(inventory.sysproduct || 'Unknown');
  const normalized_processor = normalizeName(inventory.cpuversion || 'Unknown');
  const normalized_memory = normalizeName(inventory.memory || 'Unknown');
  const normalized_storage = normalizeName(inventory.hdmodel || 'Unknown');
  const normalized_computer_type = normalizeName(inventory.systype || 'Unknown');

  // Add to results
  results.push({
    json: {
      fog_host_id: fogHost.id,
      fog_host_name: fogHost.name,
      normalized_manufacturer,
      normalized_model,
      normalized_processor,
      normalized_memory,
      normalized_storage,
      normalized_computer_type,

      // Keep original values for reference
      original_manufacturer: inventory.sysman || 'Unknown',
      original_model: inventory.sysproduct || 'Unknown',
      original_processor: inventory.cpuversion || 'Unknown',
      original_memory: inventory.memory || 'Unknown',
      original_storage: inventory.hdmodel || 'Unknown',
      original_computer_type: inventory.systype || 'Unknown'
    }
  });
}

// Return all results
return results;

// Get the extracted specs
const extractedSpecs = $json.extracted_specs;

// Collect cache matches from the merged data
const cacheMatches = [];

// Check if we have entity_type and glpi_id at root level (from PostgreSQL query)
if ($json.entity_type && $json.glpi_id && $json.name) {
  cacheMatches.push({
    entity_type: $json.entity_type,
    glpi_id: $json.glpi_id,
    name: $json.name
  });
}

// Group cache matches by entity_type for easy lookup
const matchesByType = {};
cacheMatches.forEach(match => {
  if (!matchesByType[match.entity_type]) {
    matchesByType[match.entity_type] = [];
  }
  matchesByType[match.entity_type].push(match);
});

// Map our entity types to GLPI itemtypes
const glpiItemtypeMap = {
  'manufacturer': 'Manufacturer',
  'model': 'ComputerModel',
  'processor': 'DeviceProcessor',
  'memory': 'DeviceMemory',
  'computer_type': 'ComputerType'
};

// Identify missing attributes
const missingAttributes = [];

// Check manufacturer
if (!matchesByType['manufacturer'] || matchesByType['manufacturer'].length === 0) {
  missingAttributes.push({
    entity_type: 'manufacturer',
    glpi_itemtype: 'Manufacturer',
    name: extractedSpecs.manufacturer,
    normalized_name: extractedSpecs.manufacturer_normalized
  });
}

// Check model
if (!matchesByType['model'] || matchesByType['model'].length === 0) {
  missingAttributes.push({
    entity_type: 'model',
    glpi_itemtype: 'ComputerModel',
    name: extractedSpecs.model,
    normalized_name: extractedSpecs.model_normalized
  });
}

// Check processor
if (!matchesByType['processor'] || matchesByType['processor'].length === 0) {
  missingAttributes.push({
    entity_type: 'processor',
    glpi_itemtype: 'DeviceProcessor',
    name: extractedSpecs.processor,
    normalized_name: extractedSpecs.processor_normalized
  });
}

// Check memory
if (!matchesByType['memory'] || matchesByType['memory'].length === 0) {
  missingAttributes.push({
    entity_type: 'memory',
    glpi_itemtype: 'DeviceMemory',
    name: extractedSpecs.memory,
    normalized_name: extractedSpecs.memory_normalized
  });
}

// Check computer_type
if (!matchesByType['computer_type'] || matchesByType['computer_type'].length === 0) {
  missingAttributes.push({
    entity_type: 'computer_type',
    glpi_itemtype: 'ComputerType',
    name: extractedSpecs.computer_type,
    normalized_name: extractedSpecs.computer_type_normalized
  });
}

// Add the structured data to the output
return {
  ...$json,
  cache_matches: cacheMatches,
  cache_matches_by_type: matchesByType,
  missing_attributes: missingAttributes,
  glpi_itemtype_map: glpiItemtypeMap
};

// Extract just the missing attributes array
const missingAttributes = $json.missing_attributes;

// Return an array of missing attribute objects
return missingAttributes.map(attr => ({
  ...attr,
  // Include some parent data if needed
  host_id: $json.id,
  host_name: $json.name,
  serial_number: $json.extracted_specs.serial_number
}));
